        return false;
    int min_val = getMin(arr, n);
    int max_val = getMax(arr, n);
    // Check if the range equals the number of elements
    if (max_val - min_val + 1 == n) {
        std::vector<bool> visited(n, false);  // vector of size n, all set to false
        for (int i = 0; i < n; i++) {
