bool canRepresentBST(int pre[], int n) {
    std::stack<int> s;
    int root = std::numeric_limits<int>::min();
    for (int i = 0; i < n; i++) {
        if (pre[i] < root)
            return false;
        while (!s.empty() && s.top() < pre[i]) {
            root = s.top();
            s.pop();
        }
        s.push(pre[i]);
    }
    return true;
}

