bool checkReverse(int arr[], int n) {
    if (n == 1) {
        return true;
    }
    int i;
    // Find the longest strictly increasing prefix.
    for (i = 1; i < n && arr[i - 1] < arr[i]; i++);
    if (i == n) {
        return true;
    }
    // j is set to i (postfix increment: i is increased by one after assignment)
    int j = i;
    i++;  // This mimics the behavior of "int j = i++;" in Java.
    // Process the part where elements are in descending order.
    while (j < n && arr[j] < arr[j - 1]) {
        if (i > 1 && arr[j] < arr[i - 2]) {
            return false;
        }
        j++;
    }
    if (j == n) {
        return true;
    }
    // k starts from the point after the descending sequence.
    int k = j;
    if (arr[k] < arr[i - 1]) {
        return false;
    }
    // Check that the remaining part is strictly increasing.
    while (k > 1 && k < n) {
        if (arr[k] < arr[k - 1]) {
            return false;
        }
        k++;
    }
    return true;
}

