bool isDivisible7(string num) {
    int n = num.size();
    // The original Java code seems to check for a single "0" as well.
    if (n == 0 && num[0] == '0') 
        return true;
    // Pad the string so its length is a multiple of 3.
    if (n % 3 == 1)
        num = "00" + num;
    else if (n % 3 == 2)
        num = "0" + num;
    n = num.size();
    int gSum = 0, p = 1;
    // Process the number in groups of three digits from right to left.
    for (int i = n - 1; i >= 0; i--) {
        int group = 0;
        // Extract the units digit and adjust the index.
        group += num[i--] - '0';
        // Extract the tens digit.
        group += (num[i--] - '0') * 10;
        // Extract the hundreds digit.
        group += (num[i] - '0') * 100;
        gSum = gSum + group * p;
        p = p * -1;
    }
    return (gSum % 7 == 0);
}

