void spiralFill(int m, int n, vector<vector<int>>& a) {
    int val = 1;
    int k = 0, l = 0;
    // m and n here represent the current limits (rows and columns count)
    while (k < m && l < n) {
        // Fill the top row from the remaining rows
        for (int i = l; i < n; ++i) {
            a[k][i] = val++;
        }
        ++k;
        // Fill the right column from the remaining columns
        for (int i = k; i < m; ++i) {
            a[i][n - 1] = val++;
        }
        --n;
        // Fill the bottom row from the remaining rows, if any
        if (k < m) {
            for (int i = n - 1; i >= l; --i) {
                a[m - 1][i] = val++;
            }
            --m;
        }
        // Fill the left column from the remaining columns, if any
        if (l < n) {
            for (int i = m - 1; i >= k; --i) {
                a[i][l] = val++;
            }
            ++l;
        }
    }
}

