std::string decimalToBinary(double num, int k_prec) {
    std::string binary = "";
    int Integral = static_cast<int>(num);
    double fractional = num - Integral;
    // Handle case when the integral part is zero
    if (Integral == 0)
        binary = "0";
    while (Integral > 0) {
        int rem = Integral % 2;
        binary.push_back(static_cast<char>(rem + '0'));
        Integral /= 2;
    }
    // Reverse the integral binary representation
    std::reverse(binary.begin(), binary.end());
    // Append the binary point
    binary.push_back('.');
    // Process the fractional part
    for (int i = 0; i < k_prec; i++) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= fract_bit;
            binary.push_back(static_cast<char>(1 + '0'));
        } else {
            binary.push_back(static_cast<char>(0 + '0'));
        }
    }
    return binary;
}

