int minRemove(int arr[], int n) {
    int* LIS = new int[n];
    int len = 0;
    // Initialize the LIS array with 1s.
    for (int i = 0; i < n; i++) {
        LIS[i] = 1;
    }
    // Process each element to build the longest subsequence meeting the conditions.
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j] && (i - j) <= (arr[i] - arr[j])) {
                LIS[i] = std::max(LIS[i], LIS[j] + 1);
            }
        }
        len = std::max(len, LIS[i]);
    }
    int result = n - len;
    // Free the allocated memory.
    delete[] LIS;
    return result;
}

