int countStrings(int n, int k) {
    // Create a 3D dp vector: dp[i][j][x] where i from 0 to n, j from 0 to k, x in {0, 1}
    vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(k + 1, vector<int>(2, 0)));
    // Base case: for strings of length 1, we have one way for each ending bit (0 or 1) with 0 changes.
    dp[1][0][0] = 1;
    dp[1][0][1] = 1;
    // Populate dp array for strings of length i
    for (int i = 2; i <= n; i++) {
        // j represents the number of changes so far.
        // j should be less than i (since each position could potentially be a change) and <= k.
        for (int j = 0; j < i && j <= k; j++) {
            // If current bit is 0, the previous string (of length i-1) could end in either 0 or 1.
            dp[i][j][0] = dp[i-1][j][0] + dp[i-1][j][1];
            // If current bit is 1, if the previous bit was 0, no new change. Otherwise j increases if consecutive 1's.
            dp[i][j][1] = dp[i-1][j][0];
            if (j - 1 >= 0) {
                dp[i][j][1] += dp[i-1][j-1][1];
            }
        }
    }
    // The answer is the sum of strings of length n ending in 0 or 1, with exactly k changes.
    return dp[n][k][0] + dp[n][k][1];
}

