int findSubsequenceCount(const std::string &S, const std::string &T) {
    int m = T.length();
    int n = S.length();
    if (m > n) return 0;
    // Create a (m+1) x (n+1) DP table initialized to 0.
    std::vector<std::vector<int>> mat(m + 1, std::vector<int>(n + 1, 0));
    // Base Case: for any j, an empty T (i == 0) is a subsequence of S.
    for (int j = 0; j <= n; j++) {
        mat[0][j] = 1;
    }
    // For i from 1 to m, with j = 0 the count stays 0 (by initialization),
    // so explicit initialization is optional.
    // Fill dp table
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (T[i - 1] != S[j - 1])
                mat[i][j] = mat[i][j - 1];
            else
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1];
        }
    }
    return mat[m][n];
}

