int countP(int n, int k) {
    // Create a 2D vector with dimensions (n+1) x (k+1), initialized with zeros.
    vector<vector<int>> dp(n + 1, vector<int>(k + 1, 0));
    // dp[i][0] is already 0 for all i from 0 to n.
    // Set dp[0][j] to 0 for all j from 0 to k.
    for (int j = 0; j <= k; j++) {
        dp[0][j] = 0;
    }
    // Fill the dp table using the recurrence relation.
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= k; j++) {
            if (j == 1 || i == j)
                dp[i][j] = 1;
            else
                dp[i][j] = j * dp[i - 1][j] + dp[i - 1][j - 1];
        }
    }
    return dp[n][k];
}

