int CountPS(char str[], int n) {
    std::vector<std::vector<int>> dp(n, std::vector<int>(n, 0));
    std::vector<std::vector<bool>> P(n, std::vector<bool>(n, false));
    // All substrings of length 1 are palindromic.
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
    }
    // Check for two-character palindromes.
    for (int i = 0; i < n - 1; i++) {
        if (str[i] == str[i + 1]) {
            P[i][i + 1] = true;
            dp[i][i + 1] = 1;
        }
    }
    // Fill dp[][] in bottom-up manner.
    // gap is the length of substring minus one.
    for (int gap = 2; gap < n; gap++) {
        for (int i = 0; i < n - gap; i++) {
            int j = i + gap;
            // Check for palindrome at current substring.
            if (str[i] == str[j] && P[i + 1][j - 1])
                P[i][j] = true;
            // If current substring is palindrome then
            // count it and add results of subproblems.
            if (P[i][j])
                dp[i][j] = dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1];
            else
                dp[i][j] = dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1];
        }
    }
    return dp[0][n - 1];
}

