int findgroups(int arr[], int n) {
    // counters for numbers modulo 3: index 0 -> mod 0, index 1 -> mod 1, index 2 -> mod 2
    int c[3] = {0, 0, 0};
    int res = 0;
    // Count occurrences for each remainder
    for (int i = 0; i < n; i++) {
        c[arr[i] % 3]++;
    }
    // Calculate groups where sum is divisible by 3
    // Groups with pair from remainder 0: C(c[0], 2)
    res += (c[0] * (c[0] - 1)) >> 1;
    // Groups with two numbers: one from remainder 1 and one from remainder 2
    res += c[1] * c[2];
    // Groups of three numbers from the same remainder (0, 1, or 2)
    res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6;
    res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6;
    res += (c[2] * (c[2] - 1) * (c[2] - 2)) / 6;
    // Groups with one number from each remainder: 0, 1, and 2
    res += c[0] * c[1] * c[2];
    return res;
}
