    int i = 0;
    int ans = 0;
    // Loop until (1 << i) is less or equal to n
    while ((1 << i) <= n) {
        bool k = false;
        int change = 1 << i;
        // Loop over j from 0 to n (inclusive)
        for (int j = 0; j <= n; j++) {
            if (k) {
                ans += 1;
