string decode(string str) {
    stack<int> integerStack;
    stack<char> characterStack;
    string temp = "", result = "";
    for (int i = 0; i < str.length(); i++) {
        int count = 0;
        if (isdigit(str[i])) {
            // Parse the digit(s) and push the number onto the integer stack
            while (i < str.length() && isdigit(str[i])) {
                count = count * 10 + (str[i] - '0');
                i++;
            }
            i--;  // step back to process the non-digit after the number
            integerStack.push(count);
        } else if (str[i] == ']') {
            // Reset temp to build the string inside the brackets
            temp = "";
            count = 0;
            if (!integerStack.empty()) {
                count = integerStack.top();
                integerStack.pop();
            }
            // Pop characters until the matching '[' is found
            while (!characterStack.empty() && characterStack.top() != '[') {
                temp = characterStack.top() + temp;
                characterStack.pop();
            }
            if (!characterStack.empty() && characterStack.top() == '[')
                characterStack.pop();
            // Build the repeated string
            result = "";
            for (int j = 0; j < count; j++) {
                result += temp;
            }
            // Push each character of the result back onto the character stack
            for (char c : result) {
                characterStack.push(c);
            }
            result = "";
        } else if (str[i] == '[') {
            // If the preceding character is a digit, just push '[',
            // Otherwise push '[' and assume a repeat count of 1.
            if (i > 0 && isdigit(str[i - 1]))
                characterStack.push('[');
            else {
                characterStack.push('[');
                integerStack.push(1);
            }
        } else {
            // For letters, push directly onto the character stack.
            characterStack.push(str[i]);
        }
    }
    // Build the final result string from the character stack.
    result = "";
    while (!characterStack.empty()) {
        result = characterStack.top() + result;
        characterStack.pop();
    }
    return result;
}

