int eggDrop(int n, int k) {
    // Create a 2D table eggFloor with dimensions (n+1) x (k+1)
    vector<vector<int>> eggFloor(n + 1, vector<int>(k + 1, 0));
    int res;
    // Initialize the following:
    // 1 trial for one floor and 0 trials for 0 floors
    for (int i = 1; i <= n; i++) {
        eggFloor[i][1] = 1;
        eggFloor[i][0] = 0;
    }
    // With one egg, number of trials is equal to the number of floors
    for (int j = 1; j <= k; j++) {
        eggFloor[1][j] = j;
    }
    // Fill the rest of the table using optimal substructure property
    for (int i = 2; i <= n; i++) {
        for (int j = 2; j <= k; j++) {
            eggFloor[i][j] = numeric_limits<int>::max();
            // Consider dropping the egg from each floor x and choose the minimum among all worst-case outcomes
            for (int x = 1; x <= j; x++) {
                res = 1 + max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                if (res < eggFloor[i][j])
                    eggFloor[i][j] = res;
            }
        }
    }
    return eggFloor[n][k];
}

