int lps(const std::string &seq) {
    int n = seq.length();
    // Create a 2D table to store results of subproblems
    std::vector<std::vector<int>> L(n, std::vector<int>(n, 0));
    // Every single character is a palindrome of length 1.
    for (int i = 0; i < n; i++) {
        L[i][i] = 1;
    }
    // Build the table. cl is the length of the substring.
    for (int cl = 2; cl <= n; cl++) {
        for (int i = 0; i <= n - cl; i++) {
            int j = i + cl - 1;
            if (seq[i] == seq[j] && cl == 2) {
                L[i][j] = 2;
            } else if (seq[i] == seq[j]) {
                L[i][j] = L[i + 1][j - 1] + 2;
            } else {
                L[i][j] = std::max(L[i][j - 1], L[i + 1][j]);
            }
        }
    }
    return L[0][n - 1];
}

