    // Calculate LDS (Longest Decreasing Subsequence) values for each index
    int* lds = new int[n];
    for (i = 0; i < n; i++)
        lds[i] = 1;
    for (i = n - 2; i >= 0; i--) {
        for (j = n - 1; j > i; j--) {
            if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                lds[i] = lds[j] + 1;
            }
        }
    }
    // Find the maximum value of (lis[i] + lds[i] - 1)
    int max = lis[0] + lds[0] - 1;
    for (i = 1; i < n; i++) {
        int bitonic_length = lis[i] + lds[i] - 1;
        if (bitonic_length > max)
            max = bitonic_length;
    }
    // Clean up dynamically allocated arrays
    delete[] lis;
    delete[] lds;
    return max;
