int minPalPartition(const string &str) {
    int n = str.length();
    // C[i][j] stores the minimum cuts needed for palindrome partitioning of substring str[i..j]
    vector<vector<int>> C(n, vector<int>(n, 0));
    // P[i][j] will be true if substring str[i..j] is a palindrome
    vector<vector<bool>> P(n, vector<bool>(n, false));
    // All substrings of length 1 are palindromes
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // L is the length of the substring
    for (int L = 2; L <= n; L++) {
        for (int i = 0; i <= n - L; i++) {
            int j = i + L - 1;
            if (L == 2)
                P[i][j] = (str[i] == str[j]);
            else
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            if (P[i][j])
                C[i][j] = 0;
            else {
                C[i][j] = INT_MAX;
                for (int k = i; k < j; k++) {
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }
    return C[0][n - 1];
}
