int countParenth(char symb[], char oper[], int n) {
    // Create two 2D vectors for False and True counts
    std::vector<std::vector<int>> F(n, std::vector<int>(n, 0));
    std::vector<std::vector<int>> T(n, std::vector<int>(n, 0));
    // Initialize the diagonals (base cases)
    for (int i = 0; i < n; i++) {
        F[i][i] = (symb[i] == 'F') ? 1 : 0;
        T[i][i] = (symb[i] == 'T') ? 1 : 0;
    }
    // gap represents the chain length minus one
    for (int gap = 1; gap < n; ++gap) {
        for (int i = 0, j = gap; j < n; ++i, ++j) {
            T[i][j] = 0;
            F[i][j] = 0;
            // partition the subproblem at every operator between i and j.
            for (int g = 0; g < gap; g++) {
                int k = i + g;
                int tik = T[i][k] + F[i][k];     // Total ways for left subexpression
                int tkj = T[k + 1][j] + F[k + 1][j]; // Total ways for right subexpression
                // Evaluate based on the operator at position k
                if (oper[k] == '&') {
                    T[i][j] += T[i][k] * T[k + 1][j];
                    F[i][j] += (tik * tkj - T[i][k] * T[k + 1][j]);
                }
                else if (oper[k] == '|') {
                    F[i][j] += F[i][k] * F[k + 1][j];
                    T[i][j] += (tik * tkj - F[i][k] * F[k + 1][j]);
                }
                else if (oper[k] == '^') {
                    T[i][j] += F[i][k] * T[k + 1][j] + T[i][k] * F[k + 1][j];
                    F[i][j] += T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j];
                }
            }
        }
    }
    return T[0][n - 1];
}

