bool isSubsetSum(const vector<int>& set, int n, int sum) {
    // Create a 2D vector to store the truth values for the DP solution.
    vector<vector<bool>> subset(n + 1, vector<bool>(sum + 1, false));
    // If sum is 0, answer is true for all subsets.
    for (int i = 0; i <= n; i++) {
        subset[i][0] = true;
    }
    // If there are no elements, then no non-zero sum is possible.
    for (int j = 1; j <= sum; j++) {
        subset[0][j] = false;
    }
    // Fill the subset table in bottom up manner.
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= sum; j++) {
            if (j < set[i - 1]) {
                subset[i][j] = subset[i - 1][j];
            } else {
                subset[i][j] = subset[i - 1][j] || subset[i - 1][j - set[i - 1]];
            }
        }
    }
    return subset[n][sum];
}

