long long maxPrimeFactors(long long n) {
    long long maxPrime = -1;
    // Remove the factor 2 from n
    while (n % 2 == 0) {
        maxPrime = 2;
        n >>= 1;  // equivalent to n /= 2;
    }
    // Check for odd factors up to sqrt(n)
    for (long long i = 3; i <= std::sqrt(n); i += 2) {
        while (n % i == 0) {
            maxPrime = i;
            n = n / i;
        }
    }
    // If n is a prime number greater than 2, then n itself is the largest prime factor
    if (n > 2)
        maxPrime = n;
    return maxPrime;
}

