    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(m + 1, 0));
    // Compute dp values using the provided recurrence relation
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= m; j++) {
            dp[i][j] = std::max(dp[i - 1][j - 1] + A[j - 1] * B[i - 1], dp[i][j - 1]);
        }
    }
    return dp[n][m];
}

