int binaryMedian(const vector<vector<int>>& m, int r, int c) {
    int minVal = INT_MAX;
    int maxVal = INT_MIN;
    // Determine the overall minimum and maximum in the matrix.
    for (int i = 0; i < r; i++) {
        if (m[i][0] < minVal)
            minVal = m[i][0];
        if (m[i][c - 1] > maxVal)
            maxVal = m[i][c - 1];
    }
    int desired = (r * c + 1) / 2;
    // Binary search the answer between minVal and maxVal.
    while (minVal < maxVal) {
        int mid = minVal + (maxVal - minVal) / 2;
        int place = 0;
        // Use upper_bound to count the number of elements <= mid in each row.
        for (int i = 0; i < r; i++) {
            // upper_bound returns iterator to first element greater than mid.
            // The distance from begin to that iterator is the count of elements <= mid.
            place += upper_bound(m[i].begin(), m[i].end(), mid) - m[i].begin();
        }
        // Adjust search range depending on the count.
        if (place < desired)
            minVal = mid + 1;
        else
            maxVal = mid;
    }
    return minVal;
}

