    int n = b.length();
    std::vector<std::vector<int>> lookup(m + 1, std::vector<int>(n + 1, 0));
    // Initialize first row (0-th row) to 0
    for (int i = 0; i <= n; ++i)
        lookup[0][i] = 0;
    // Initialize first column (0-th column) to 1
    for (int i = 0; i <= m; ++i)
        lookup[i][0] = 1;
    // Build the lookup table in a bottom-up manner
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (a[i - 1] == b[j - 1])
                lookup[i][j] = lookup[i - 1][j - 1] + lookup[i - 1][j];
            else
                lookup[i][j] = lookup[i - 1][j];
        }
    }
    return lookup[m][n];
}

