int pairsInSortedRotated(int arr[], int n, int x) {
    int i;
    // Find the pivot point where the array rotation occurred.
    for (i = 0; i < n - 1; i++) {
        if (arr[i] > arr[i + 1])
            break;
    }
    // l is the index of the smallest element.
    int l = (i + 1) % n;
    // r is the index of the largest element.
    int r = i;
    int cnt = 0;
    // Loop until the two pointers meet.
    while (l != r) {
        int sum = arr[l] + arr[r];
        if (sum == x) {
            cnt++;
            // If there is only one pair possible, return the count.
            if (l == (r - 1 + n) % n) {
                return cnt;
            }
            l = (l + 1) % n;
            r = (r - 1 + n) % n;
        }
        // If sum is less than x, move the left pointer to get a larger sum.
        else if (sum < x) {
            l = (l + 1) % n;
        }
        // If sum is greater than x, move the right pointer to get a smaller sum.
        else {
            r = (r - 1 + n) % n;
        }
    }
    return cnt;
}

