int kthLargestSum(const vector<int>& arr, int n, int k) {
    // Create prefix sum array
    vector<int> prefix(n + 1, 0);
    prefix[0] = 0;
    if(n > 0) {
        prefix[1] = arr[0];
    }
    for (int i = 2; i <= n; i++) {
        prefix[i] = prefix[i - 1] + arr[i - 1];
    }
    // Using a min heap to store the k largest subarray sums
    priority_queue<int, vector<int>, greater<int>> minHeap;
    // Calculate all subarray sums and maintain the k largest in the heap
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= n; j++) {
            int x = prefix[j] - prefix[i - 1];
            if (minHeap.size() < k) {
                minHeap.push(x);
            } else if (minHeap.top() < x) {
                minHeap.pop();
                minHeap.push(x);
            }
        }
    }
    return minHeap.top();
}
