int lengthOfLongestAP(const vector<int>& set) {
    int n = set.size();
    if (n <= 2)
        return n;
    // Create a 2D vector to store the lengths of arithmetic progressions.
    vector<vector<int>> L(n, vector<int>(n, 0));
    int llap = 2;  // Length of longest arithmetic progression
    // Initialize the last column as 2.
    for (int i = 0; i < n; ++i)
        L[i][n - 1] = 2;
    // Consider every element as the second last element of AP
    for (int j = n - 2; j >= 1; --j) {
        int i = j - 1, k = j + 1;
        // Search for i and k for current j
        while (i >= 0 && k <= n - 1) {
            if (set[i] + set[k] < 2 * set[j])
                ++k;
            else if (set[i] + set[k] > 2 * set[j]) {
                L[i][j] = 2;
                --i;
            } else {
                // Found i and k such that set[i], set[j], set[k] form an AP
                L[i][j] = L[j][k] + 1;
                llap = max(llap, L[i][j]);
                --i;
                ++k;
            }
        }
        // Set remaining L[i][j] as 2 for all i before the start of the current j.
        while (i >= 0) {
            L[i][j] = 2;
            --i;
        }
    }
    return llap;
}

