int lcs(vector<vector<vector<int>>>& dp, const vector<int>& arr1, int n, const vector<int>& arr2, int m, int k) {
    // k < 0 means no more allowed modifications – return a very negative value.
    if (k < 0) return -10000000;
    // if any of the arrays is exhausted, there is no common subsequence.
    if (n < 0 || m < 0) return 0;
    // Use memoization table: if already computed, return stored value.
    int& ans = dp[n][m][k];
    if (ans != -1) return ans;
    // Option 1: Skip an element from arr1 or arr2.
    ans = max(lcs(dp, arr1, n - 1, arr2, m, k),
              lcs(dp, arr1, n, arr2, m - 1, k));
    // Option 2: If the last elements of current segments match,
    // add this element to the result.
    if (arr1[n - 1] == arr2[m - 1])
        ans = max(ans, 1 + lcs(dp, arr1, n - 1, arr2, m - 1, k));
    // Option 3: Regardless of matching, try pairing by spending 1 modification.
    ans = max(ans, 1 + lcs(dp, arr1, n - 1, arr2, m - 1, k - 1));
    return ans;
}

