std::string longestRepeatedSubSeq(const std::string &str) {
    int n = str.length();
    // Create a dp table with dimensions (n+1) x (n+1) initialized to 0.
    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(n + 1, 0));
    // Fill dp table; note that dp[i][j] is computed based on comparing characters of str.
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (str[i - 1] == str[j - 1] && i != j)
                dp[i][j] = 1 + dp[i - 1][j - 1];
            else
                dp[i][j] = std::max(dp[i - 1][j], dp[i][j - 1]);
        }
    }
    // Reconstruct the longest repeated subsequence from the dp table.
    std::string res = "";
    int i = n, j = n;
    while (i > 0 && j > 0) {
        if (dp[i][j] == dp[i - 1][j - 1] + 1) {
            res.push_back(str[i - 1]);
            i--;
            j--;
        } else if (dp[i][j] == dp[i - 1][j]) {
            i--;
        } else {
            j--;
        }
    }
    // Since the subsequence was built backwards, reverse it.
    std::reverse(res.begin(), res.end());
    return res;
}
