                palin[l] = '9';
            }
        }
        // If the digit is not '9', try to update it.
        if(palin[l] < '9') {
            // Check if we can change both digits to '9'.
            // Case 1: Both digits were untouched (same as original)
            if(k >= 2 && palin[l] == str[l] && palin[r] == str[r]) {
                k -= 2;
                palin[l] = palin[r] = '9';
            }
            // Case 2: At least one digit was already changed in the first pass.
            else if(k >= 1 && (palin[l] != str[l] || palin[r] != str[r])) {
                k--;
                palin[l] = palin[r] = '9';
            }
        }
        l++;
        r--;
    }
    return palin;
}
