int findMaxVal(const vector<int>& arr, int n, int num, int maxLimit) {
    // Create a DP table with n rows and (maxLimit + 1) columns, initialized with 0.
    vector<vector<int>> dp(n, vector<int>(maxLimit + 1, 0));
    for (int ind = 0; ind < n; ind++) {
        for (int val = 0; val <= maxLimit; val++) {
            if (ind == 0) {
                if (num - arr[ind] == val || num + arr[ind] == val)
                    dp[ind][val] = 1;
                else
                    dp[ind][val] = 0;
            } else {
                // Prepare for both possible moves
                bool possible1 = false;
                bool possible2 = false;
                if (val - arr[ind] >= 0) {
                    possible1 = (dp[ind - 1][val - arr[ind]] == 1);
                }
                if (val + arr[ind] <= maxLimit) {
                    possible2 = (dp[ind - 1][val + arr[ind]] == 1);
                }
                dp[ind][val] = (possible1 || possible2) ? 1 : 0;
            }
        }
    }
    for (int val = maxLimit; val >= 0; val--) {
        if (dp[n - 1][val] == 1)
            return val;
    }
    return -1;
}

