    // Loop over the array starting from the second element.
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[j] > arr[i]) {
                // Build a "decreasing" sequence.
                dec[i] = max(dec[i], inc[j] + arr[i]);
                flag = 1;
            }
            else if (arr[j] < arr[i] && flag == 1) {
                // Build an "increasing" sequence only if a valid decreasing sequence was set.
                inc[i] = max(inc[i], dec[j] + arr[i]);
            }
        }
    }
    // Find the maximum value from both sequences.
    int result = INT_MIN;
    for (int i = 0; i < n; i++) {
        result = max(result, inc[i]);
        result = max(result, dec[i]);
    }
    return result;
}

