int getMinDiff(int arr[], int n, int k) {
    if (n == 1)
        return 0;
    std::sort(arr, arr + n);
    int ans = arr[n - 1] - arr[0];
    int small = arr[0] + k;
    int big = arr[n - 1] - k;
    // Ensure small is the smaller value and big is the larger one.
    if (small > big) {
        std::swap(small, big);
    }
    // Loop through the middle elements.
    for (int i = 1; i < n - 1; i++) {
        int subtract = arr[i] - k;
        int add = arr[i] + k;
        // If the current change does not improve the situation, skip it.
        if (subtract >= small || add <= big)
            continue;
        // Decide whether to update small or big
        if (big - subtract <= add - small)
            small = subtract;
        else
            big = add;
    }
    return std::min(ans, big - small);
}

