int MinimumCost(const vector<int>& cost, int n, int W) {
    vector<int> val; // store cost values for available coins
    vector<int> wt;  // store weights (i+1) corresponding to cost
    int size = 0;
    // Build the lists: only include items with cost != -1
    for (int i = 0; i < n; i++) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1);
            size++;
        }
    }
    n = size; // update n to the number of available items
    // Create dp table: min_cost[i][j] where i = number of items considered and j = total weight
    vector<vector<int>> min_cost(n + 1, vector<int>(W + 1, INT_MAX));
    // For 0 items, the cost for positive weight (j > 0) cannot be achieved, hence INT_MAX
    for (int j = 0; j <= W; j++) {
        min_cost[0][j] = INT_MAX;
    }
    // When required weight is 0, no cost is needed
    for (int i = 0; i <= n; i++) {
        min_cost[i][0] = 0;
    }
    // Build the dp table, similar to unbounded knapsack
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= W; j++) {
            if (wt[i - 1] > j) {
                // Cannot use the i-th item since its weight is more than the current required weight
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                // Option: Do not include the item OR include the item (unbounded choice)
                if (min_cost[i][j - wt[i - 1]] != INT_MAX) {
                    min_cost[i][j] = min(min_cost[i - 1][j],
                                         min_cost[i][j - wt[i - 1]] + val[i - 1]);
                } else {
                    min_cost[i][j] = min_cost[i - 1][j];
                }
            }
        }
    }
    return (min_cost[n][W] == INT_MAX) ? -1 : min_cost[n][W];
}

