int minJumps(int arr[], int n) {
    // If the array is empty or the first element is 0, it's impossible to move forward.
    if (n == 0 || arr[0] == 0)
        return INT_MAX;
    // Create an array to store the minimum number of jumps to reach each index.
    int* jumps = new int[n];
    jumps[0] = 0;
    // Fill the rest of the jumps array.
    for (int i = 1; i < n; i++) {
        // Initialize this position as unreachable.
        jumps[i] = INT_MAX;
        for (int j = 0; j < i; j++) {
            // Check if index i is reachable from index j
            if (i <= j + arr[j] && jumps[j] != INT_MAX) {
                jumps[i] = std::min(jumps[i], jumps[j] + 1);
                break; // Once we found a valid jump, break out of the inner loop.
            }
        }
    }
    int result = jumps[n - 1];
    delete[] jumps;  // Clean up allocated memory.
    return result;
}

