static bool isPrime(int p) {
    // In C++ we can use bit shifting to compute 2^p. Note: this works correctly
    // when p is small enough that (1ULL << p) does not overflow.
    unsigned long long checkNumber = ((1ULL << p) - 1);
    unsigned long long nextval = 4 % checkNumber;
    for (int i = 1; i < p - 1; i++) {
        nextval = (nextval * nextval - 2) % checkNumber;
    }
    return (nextval == 0);
}

