void antiSpiralTraversal(int m, int n, const vector<vector<int>>& a) {
    int i, k = 0, l = 0;
    stack<int> stk;
    // Here, m and n represent the last valid indices (rows-1 and columns-1 respectively).
    while (k <= m && l <= n) {
        // Traverse the top row from the current left to right boundary.
        for (i = l; i <= n; i++) {
            stk.push(a[k][i]);
        }
        k++;
        // Traverse the rightmost column from the current top to bottom boundary.
        for (i = k; i <= m; i++) {
            stk.push(a[i][n]);
        }
        n--;
        // Traverse the bottom row from right to left, if rows remain.
        if (k <= m) {
            for (i = n; i >= l; i--) {
                stk.push(a[m][i]);
            }
            m--;
        }
        // Traverse the leftmost column from bottom to top, if columns remain.
        if (l <= n) {
            for (i = m; i >= k; i--) {
                stk.push(a[i][l]);
            }
            l++;
        }
    }
    // Pop from the stack to print the elements in anti-spiral order.
    while (!stk.empty()) {
        cout << stk.top() << " ";
        stk.pop();
    }
}

