string censor(string text, string word) {
    // Split the text using whitespace into a vector of words.
    istringstream iss(text);
    vector<string> wordList;
    string token;
    while (iss >> token) {
        wordList.push_back(token);
    }
    // Create a string of '*' that is the same length as the word.
    string stars(word.size(), '*');
    // Replace occurrences of the word with stars.
    for (auto &w : wordList) {
        if (w == word) {
            w = stars;
        }
    }
    // Reassemble the string from the vector.
    string result;
    for (const auto &w : wordList) {
        result += w + " ";
    }
    return result;
}
