std::string recursiveReverse(std::vector<char>& str) {
    std::stack<char> st;
    // Push each character onto the stack
    for (char ch : str) {
        st.push(ch);
    }
    // Pop characters from the stack to reverse the array
    for (size_t i = 0; i < str.size(); i++) {
        str[i] = st.top();
        st.pop();
    }
    // Convert the vector back to a string and return it
    return std::string(str.begin(), str.end());
}

