void rearrange(int arr[], int n) {
    int max_idx = n - 1, min_idx = 0;
    int max_elem = arr[n - 1] + 1; // A number greater than the maximum element in arr
    // Modify the array elements
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) {
            arr[i] += (arr[max_idx] % max_elem) * max_elem;
            max_idx--;
        } else {
            arr[i] += (arr[min_idx] % max_elem) * max_elem;
            min_idx++;
        }
    }
    // Divide each element by max_elem to get the final rearranged array
    for (int i = 0; i < n; i++) {
        arr[i] = arr[i] / max_elem;
    }
}
