int selectRandom(int x) {
    // In the Java version, count is incremented on every call.
    // In order to mimic that behavior across calls, we make count static.
    static int count = 0;
    int res = 0;
    count++;
    if (count == 1) {
        res = x;
    } else {
        // Create a new RNG every call (similar to new Random() in Java)
        std::random_device rd;
        std::mt19937 gen(rd());
        // Uniform integer in [0, count-1]
        std::uniform_int_distribution<> dis(0, count - 1);
        int i = dis(gen);
        if (i == count - 1) {
            res = x;
        }
    }
    return res;
}

