int KnapSack(const int val[], const int wt[], int n, int W) {
    // Create a 2 x (W+1) matrix initialized to zero
    vector<vector<int>> mat(2, vector<int>(W + 1, 0));
    int i = 0;
    while (i < n) {
        int j = 0;
        // Process based on whether i is even or odd
        if (i % 2 != 0) {
            while (++j <= W) {
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                } else {
                    mat[1][j] = mat[0][j];
                }
            }
        } else {
            while (++j <= W) {
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                } else {
                    mat[0][j] = mat[1][j];
                }
            }
        }
        i++;
    }
