int sumoflength(const vector<int>& arr) {
    int n = arr.size();
    unordered_set<int> s;
    int j = 0;
    int ans = 0;
    for (int i = 0; i < n; i++) {
        while (j < n && s.find(arr[j]) == s.end()) {
            s.insert(arr[j]);
            j++;
        }
        int length = j - i;
        ans += (length * (length + 1)) / 2;
        s.erase(arr[i]);
    }
    return ans;
}

