int binomialCoeffSum(int n) {
    std::vector<std::vector<int>> C(n + 1, std::vector<int>(n + 1, 0));
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= std::min(i, n); j++) {
            if (j == 0 || j == i) {
                C[i][j] = 1;
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    int sum = 0;
    for (int i = 0; i <= n; i++) {
        sum += C[n][i];
    }
    return sum;
}

