int divSum(int n) {
    int result = 0;
    for (int i = 2; i <= std::sqrt(n); i++) {
        if (n % i == 0) {
            if (i == n / i)
                result += i;
            else
                result += i + n / i;
        }
    }
    return result + n + 1;
}

