int sumofsquare(int n) {
    // Create a 2D array of size (n+1) x (n+1)
    int** C = new int*[n + 1];
    for (int i = 0; i <= n; i++) {
        C[i] = new int[n + 1];
    }
    // Compute the binomial coefficients using Pascal's Rule.
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= min(i, n); j++) {
            if (j == 0 || j == i) {
                C[i][j] = 1;
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    // Compute the sum of squares of the coefficients in the n-th row.
    int sum = 0;
    for (int i = 0; i <= n; i++) {
        sum += (C[n][i] * C[n][i]);
    }
    // Free allocated memory.
    for (int i = 0; i <= n; i++) {
        delete[] C[i];
    }
    delete[] C;
    return sum;
}
