string findSum(string str1, string str2) {
    // Ensure str1 is the smaller string
    if (str1.length() > str2.length()) {
        swap(str1, str2);
    }
    int n1 = str1.size();
    int n2 = str2.size();
    // Reverse both strings
    reverse(str1.begin(), str1.end());
    reverse(str2.begin(), str2.end());
    string result;
    int carry = 0;
    // Add digits of both strings up to the length of the smaller string
    int i = 0;
    for (; i < n1; i++) {
        int sum = (str1[i] - '0') + (str2[i] - '0') + carry;
        result.push_back((sum % 10) + '0');
        carry = sum / 10;
    }
    // Process remaining digits of the longer string
    for (; i < n2; i++) {
        int sum = (str2[i] - '0') + carry;
        result.push_back((sum % 10) + '0');
        carry = sum / 10;
    }
    // If there is any remaining carry, add it as well
    if (carry > 0) {
        result.push_back(carry + '0');
    }
    // Reverse the result to get the final sum in proper order
    reverse(result.begin(), result.end());
    return result;
}

