static int swapBits(int x, int p1, int p2, int n) {
    int set1 = (x >> p1) & ((1 << n) - 1);
    int set2 = (x >> p2) & ((1 << n) - 1);
    int xorVal = set1 ^ set2;
    xorVal = (xorVal << p1) | (xorVal << p2);
    int result = x ^ xorVal;
    return result;
}

