int countWays(int n) {
    // Create two vectors of size n+1
    std::vector<int> A(n + 1);
    std::vector<int> B(n + 1);
    // Initialize base cases
    A[0] = 1;
    A[1] = 0;
    B[0] = 0;
    B[1] = 1;
    // Compute values for indices from 2 to n
    for (int i = 2; i <= n; i++) {
        A[i] = A[i - 2] + 2 * B[i - 1];
        B[i] = A[i - 1] + B[i - 2];
    }
    return A[n];
}

