int countUnique(const vector<vector<int>>& mat, int n, int m) {
    vector<int> rowsum(n, 0);
    vector<int> colsum(m, 0);
    // Count non-zero elements for each row and column
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (mat[i][j] != 0) {
                rowsum[i]++;
                colsum[j]++;
            }
        }
    }
    // Count unique non-zero elements where the element
    // is the only non-zero in its row and its column
    int uniquecount = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (mat[i][j] != 0 && rowsum[i] == 1 && colsum[j] == 1) {
                uniquecount++;
            }
        }
    }
    return uniquecount;
}

