int countTransformation(const string &a, const string &b) {
    int n = a.length(), m = b.length();
    if (m == 0) {
        return 1;
    }
    // Create a dp 2D vector with dimensions m x n and initialize with zeros
    vector<vector<int>> dp(m, vector<int>(n, 0));
    // Loop over each character in b (i) and a (j)
    for (int i = 0; i < m; i++) {
        for (int j = i; j < n; j++) {
            if (i == 0) {
                if (j == 0) {
                    dp[i][j] = (a[j] == b[i]) ? 1 : 0;
                }
                else if (a[j] == b[i]) {
                    dp[i][j] = dp[i][j - 1] + 1;
                }
                else {
                    dp[i][j] = dp[i][j - 1];
                }
            }
            else {
                if (a[j] == b[i]) {
                    dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                }
                else {
                    dp[i][j] = dp[i][j - 1];
                }
            }
        }
    }
    return dp[m - 1][n - 1];
}

